What is the output?
int count = 0;
void rec(int n) {
  if (n <= 0) return;
  count++;
  rec(n-1);
  rec(n-1);
}
rec(3);
printf("%d", count);

What is the output?
int fib(int n) {
  if (n <= 1) return n;
  return fib(n-1) + fib(n-2);
}
printf("%d", fib(0) + fib(1) + fib(2));

What is the output?
for (int i = 1; i <= 3; i++) {
  int j = 1;
  while (j <= i) {
    printf("* ");
    j++;
  }
  printf("\n");
}

explanation:
i=1: inner loop runs once (*
), i=2: inner loop runs twice (**
), i=3: inner loop runs thrice (***
). This is a classic right triangle star pattern.

